    for i in 0..nup {
        let desc = &child_proto.upvalues[i];
        let uv = if desc.instack {
            let level = base + desc.idx as i32;
            crate::func::find_upval(self, level)
        } else {
            parent_cl.upvals[desc.idx as usize].clone()
        };
        upvals.push(uv);
    }
